                    borderRadius: 'var(--radius-sm)',
                    border: '1px solid rgba(239, 68, 68, 0.35)',
                    cursor: 'pointer',
                    background: 'rgba(239, 68, 68, 0.08)',
                    color: '#ef4444',
                    fontWeight: 600,
                    fontSize: '13px',
                  }}
                >
                  {kickingIds[String(memberId)] ? '...' : 'đŸ« Kick'}
                </button>
              )}
            </div>
          </div>
        );
      })}
    </div>
  );
}

import { useState, useRef, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import useNotifications from '@/hooks/useNotifications';
import NotificationItem from './NotificationItem';

export default function NotificationBell({ userId }) {
  const navigate = useNavigate();
  const {
    notifs,
    seen,
    unreadCount,
    processing,
    markAllRead,
    acceptInvite,
    declineInvite,
    acceptFriendRequest,
    declineFriendRequest
  } = useNotifications(userId);

  const [open, setOpen] = useState(false);
  const btnRef = useRef(null);
  const [dropPos, setDropPos] = useState({ top: 0, left: 0 });

  const handleOpen = () => {
    if (!open && btnRef.current) {
      const rect = btnRef.current.getBoundingClientRect();
      const dropW = 360;
      let left = rect.left;
      if (left + dropW > window.innerWidth - 8) {
        left = window.innerWidth - dropW - 8;
      }
      if (left < 8) left = 8;
      setDropPos({ top: rect.bottom + 8, left });
    }
    setOpen((o) => {
      if (o) {
        markAllRead();
      }
      return !o;
    });
  };

  const handleActionClick = (n) => {
    navigate(`/groups/${n.groupId}?tab=deadlines`);
    markAllRead();
    setOpen(false);
  };

  const onAcceptInvite = (n) => {
    acceptInvite(n.inviteId, n.groupId);
  };

  const onDeclineInvite = (n) => {
    declineInvite(n.inviteId);
  };

  const onAcceptFriend = (n) => {
    acceptFriendRequest(n.requestId);
  };

  const onDeclineFriend = (n) => {
    declineFriendRequest(n.requestId);
  };

  return (
    <div style={{ position: 'relative' }}>
      <button
        ref={btnRef}
        onClick={handleOpen}
        title="ThĂ´ng bĂ¡o"
        style={{
          background: open ? 'rgba(108,99,255,0.15)' : 'transparent',
          border: 'none',
          borderRadius: '0 13px 13px 0',
          width: 'auto',
          height: 54,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          cursor: 'pointer',
          position: 'relative',
          transition: 'background 0.2s',
          flexDirection: 'row',
          gap: '5px',
          padding: '0 14px',
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.background = 'rgba(108,99,255,0.1)';
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.background = open ? 'rgba(108,99,255,0.15)' : 'transparent';
        }}
      >
        <span style={{ fontSize: 20, lineHeight: 1, flexShrink: 0 }}>đŸ””</span>
        {unreadCount > 0 && (
          <span
            style={{
              background: '#ef4444',
              color: '#fff',
              borderRadius: '8px',
              minWidth: 20,
              height: 20,
              fontSize: 11,
              fontWeight: 800,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              padding: '0 5px',
              lineHeight: 1,
              whiteSpace: 'nowrap',
              boxSizing: 'border-box',
              flexShrink: 0,
            }}
          >
            {unreadCount > 999 ? '999+' : unreadCount}
          </span>
        )}
      </button>

      {open && (
        <>
          {/* Backdrop to close */}
          <div
            onClick={() => {
              markAllRead();
              setOpen(false);
            }}
            style={{ position: 'fixed', inset: 0, zIndex: 8999 }}
          />
          <div
            style={{
              position: 'fixed',
              top: dropPos.top,
              left: dropPos.left,
              width: 360,
              maxHeight: 480,
              background: 'var(--bg-card)',
              border: '1px solid var(--border)',
              borderRadius: '16px',
              boxShadow: '0 8px 32px rgba(0,0,0,0.4)',
              zIndex: 9000,
              overflow: 'hidden',
              display: 'flex',
              flexDirection: 'column',
            }}
          >
            <div
              style={{
                padding: '14px 16px',
                borderBottom: '1px solid var(--border)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'space-between',
              }}
            >
              <span style={{ fontWeight: 700, fontSize: 15 }}>đŸ”” ThĂ´ng bĂ¡o</span>
              {notifs.length > 0 && (
                <button
                  onClick={markAllRead}
                  style={{
                    background: 'none',
                    border: 'none',
                    color: 'var(--primary)',
                    fontSize: 12,
                    cursor: 'pointer',
                    fontWeight: 600,
                  }}
                >
                  ÄĂ¡nh dáº¥u Ä‘Ă£ Ä‘á»c
                </button>
              )}
            </div>
            <div style={{ overflowY: 'auto', flex: 1 }}>
              {notifs.length === 0 ? (
                <div style={{ padding: '32px 16px', textAlign: 'center', color: 'var(--text-muted)', fontSize: 14 }}>
                  KhĂ´ng cĂ³ thĂ´ng bĂ¡o nĂ o
                </div>
              ) : (
                notifs.map((n) => {
                  const isUnread = !seen.has(n.key);
                  const procKey = n.inviteId || n.requestId;
                  const proc = processing[procKey];
                  return (
                    <NotificationItem
                      key={n.key}
                      notification={n}
                      isUnread={isUnread}
                      isProcessing={proc}
                      onAccept={onAcceptInvite}
                      onDecline={onDeclineInvite}
                      onAcceptFriend={onAcceptFriend}
                      onDeclineFriend={onDeclineFriend}
                      onActionClick={handleActionClick}
                    />
                  );
                })
              )}
            </div>
          </div>
        </>
      )}
    </div>
  );
}

import { useState, useRef } from 'react';
import Avatar from '@/components/common/Avatar';
import { timeAgo } from '@/utils';
import LikeCommentBar from './LikeCommentBar';
import CommentRow from './CommentRow';

export default function PostCard({ post, currentUser, onLike, onDelete, onComment }) {
  const [showComments, setShowComments] = useState(false);
  const [commentText, setCommentText] = useState('');
  const [expanded, setExpanded] = useState(false);
  const [replyTo, setReplyTo] = useState(null); // { id, name }
  const [commentReactions, setCommentReactions] = useState({}); // commentId -> emoji string or null

  const isLong = post.content.length > 200;
  const myLike = Array.isArray(post.likes)
    ? post.likes.find((l) => (typeof l === 'object' ? l.userId : l) === currentUser?.id)
    : null;
  const isLiked = !!myLike;
  const likedEmoji = typeof myLike === 'object' ? myLike?.emoji : null;
  const isOwner = post.userId === currentUser?.id;

  const handleComment = () => {
    if (!commentText.trim()) return;
    const finalText = commentText.trim();
    onComment(post.id, finalText, replyTo ? { id: replyTo.id, name: replyTo.name } : null);
    setCommentText('');
    setReplyTo(null);
  };

  const tagColorMap = {
    'ToĂ¡n - LĂ½': '#f59e0b',
    'Láº­p trĂ¬nh': '#3ecfcf',
    'Kinh táº¿': '#22c55e',
    'Ngoáº¡i ngá»¯': '#6c63ff',
    'ThĂ´ng bĂ¡o': '#ef4444',
  };
  const tagColor = tagColorMap[post.tag] || '#8b92b8';

  return (
    <article
      style={{
        background: 'var(--bg-card)',
        border: '1px solid var(--border)',
        borderRadius: '18px',
        marginBottom: '14px',
        overflow: 'hidden',
        transition: 'border-color 0.2s, box-shadow 0.2s',
      }}
      onMouseEnter={(e) => {
        e.currentTarget.style.borderColor = 'rgba(108,99,255,0.4)';
        e.currentTarget.style.boxShadow = '0 4px 24px rgba(108,99,255,0.08)';
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.borderColor = 'var(--border)';
        e.currentTarget.style.boxShadow = 'none';
      }}
    >
      {/* Author row */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '12px', padding: '16px 18px 0' }}>
        <Avatar src={post.userAvatar} initial={post.userInitial} size={46} />
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', flexWrap: 'wrap' }}>
            <span style={{ fontWeight: 700, fontSize: '15px', color: 'var(--text-primary)' }}>
              {post.userFullName}
            </span>
            {post.tag && (
              <span
                style={{
                  fontSize: '11px',
                  fontWeight: 700,
                  padding: '2px 9px',
                  borderRadius: '20px',
                  background: `${tagColor}22`,
                  color: tagColor,
                  border: `1px solid ${tagColor}44`,
                }}
              >
                {post.tag}
              </span>
            )}
          </div>
          <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginTop: '3px' }}>
            {post.university && `đŸ« ${post.university} Â· `}
            {timeAgo(post.createdAt)}
          </div>
        </div>
        {isOwner && (
          <button
            onClick={() => onDelete(post.id)}
            title="XĂ³a bĂ i"
            style={{
              background: 'none',
              border: 'none',
              cursor: 'pointer',
              color: 'var(--text-muted)',
              fontSize: '18px',
              padding: '4px 8px',
              borderRadius: '8px',
              lineHeight: 1,
              transition: 'color 0.15s',
            }}
            onMouseEnter={(e) => (e.currentTarget.style.color = '#ef4444')}
            onMouseLeave={(e) => (e.currentTarget.style.color = 'var(--text-muted)')}
          >
            đŸ—‘
          </button>
        )}
      </div>

      {/* Content */}
      <div style={{ padding: '12px 18px 14px' }}>
        <p style={{ fontSize: '15px', lineHeight: 1.75, color: 'var(--text-primary)', margin: 0, whiteSpace: 'pre-wrap' }}>
          {isLong && !expanded ? post.content.slice(0, 200) + 'â€¦' : post.content}
        </p>
        {isLong && (
          <button
            onClick={() => setExpanded((v) => !v)}
            style={{
              background: 'none',
              border: 'none',
              cursor: 'pointer',
              color: 'var(--primary-light)',
              fontWeight: 600,
              fontSize: '13px',
              padding: '4px 0 0',
              fontFamily: 'inherit',
            }}
          >
            {expanded ? 'â–² Thu gá»n' : 'â–¼ Xem thĂªm'}
          </button>
        )}
      </div>

      {/* Stats row */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          padding: '0 18px 10px',
          fontSize: '12px',
          color: 'var(--text-muted)',
        }}
      >
        <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
          {post.likes && post.likes.length > 0 && (() => {
            const emojis = [
              ...new Set(
                post.likes.map((l) => (typeof l === 'object' ? l.emoji : 'đŸ’œ')).filter(Boolean)
              ),
            ].slice(0, 3);
            return (
              <>
                <span>{emojis.join('')}</span>
                <span>{post.likes.length} lÆ°á»£t thĂ­ch</span>
              </>
            );
          })()}
        </span>
        <span style={{ cursor: 'pointer' }} onClick={() => setShowComments((v) => !v)}>
          {post.comments && post.comments.length > 0 && `${post.comments.length} bĂ¬nh luáº­n`}
        </span>
      </div>

      {/* Divider */}
      <div style={{ height: '1px', background: 'var(--border)', margin: '0 18px' }} />

      {/* Action buttons */}
      <LikeCommentBar
        post={post}
        isLiked={isLiked}
        likedEmoji={likedEmoji}
        showComments={showComments}
        onLike={(em) => onLike(post.id, em)}
        onToggleComments={() => setShowComments((v) => !v)}
      />

      {/* Comments section */}
      {showComments && (
        <div style={{ borderTop: '1px solid var(--border)', padding: '12px 18px 14px' }}>
          {/* Threaded comments tree */}
          {post.comments && post.comments.length > 0 && (() => {
            const roots = post.comments.filter((c) => !c.parentId);
            const repliesOf = (pid) => post.comments.filter((c) => c.parentId === pid);
            const renderComment = (c, depth = 0) => {
              const replies = repliesOf(c.id);
              return (
                <div key={c.id}>
                  <CommentRow
                    comment={c}
                    liked={!!commentReactions[c.id]}
                    likedEmoji={commentReactions[c.id] || null}
                    onLike={(em) =>
                      setCommentReactions((prev) => ({
                        ...prev,
                        [c.id]: prev[c.id] && !em ? null : em || 'đŸ‘',
                      }))
                    }
                    onReply={() => {
                      setReplyTo({ id: c.id, name: c.userFullName });
                      setShowComments(true);
                      setTimeout(
                        () => document.getElementById(`comment-input-${post.id}`)?.focus(),
                        80
                      );
                    }}
                  />
                  {replies.length > 0 && (
                    <div
                      style={{
                        marginLeft: depth < 1 ? '40px' : '20px',
                        marginTop: '8px',
                        paddingLeft: '12px',
                        borderLeft: '2px solid var(--border)',
                        display: 'flex',
                        flexDirection: 'column',
                        gap: '8px',
                      }}
                    >
                      {replies.map((r) => renderComment(r, depth + 1))}
                    </div>
                  )}
                </div>
              );
            };
            return (
              <div style={{ marginBottom: '12px', display: 'flex', flexDirection: 'column', gap: '10px' }}>
                {roots.map((c) => renderComment(c))}
              </div>
            );
          })()}

          {/* Write comment */}
          {currentUser && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
              {replyTo && (
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px', padding: '4px 0 0 40px' }}>
                  <span style={{ fontSize: '12px', color: 'var(--primary-light)', fontWeight: 600 }}>
                    â†©ï¸ Äang tráº£ lá»i <strong>{replyTo.name}</strong>
                  </span>
                  <button
                    onClick={() => setReplyTo(null)}
                    style={{
                      background: 'none',
                      border: 'none',
                      cursor: 'pointer',
                      color: 'var(--text-muted)',
                      fontSize: '13px',
                      padding: 0,
                      lineHeight: 1,
                    }}
                  >
                    âœ•
                  </button>
                </div>
              )}
              <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
                <Avatar
                  src={currentUser.avatar}
                  initial={(currentUser.fullName || 'U')[0]}
                  size={30}
                />
                <div
                  style={{
                    flex: 1,
                    display: 'flex',
                    background: 'var(--bg-input)',
                    border: '1px solid var(--border)',
                    borderRadius: '20px',
                    overflow: 'hidden',
                  }}
                >
                  <input
                    id={`comment-input-${post.id}`}
                    value={commentText}
                    onChange={(e) => setCommentText(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleComment()}
                    placeholder={replyTo ? `Tráº£ lá»i ${replyTo.name}...` : 'Viáº¿t bĂ¬nh luáº­n...'}
                    style={{
                      flex: 1,
                      background: 'none',
                      border: 'none',
                      outline: 'none',
                      padding: '8px 14px',
                      color: 'var(--text-primary)',
                      fontSize: '13px',
                      fontFamily: 'inherit',
                    }}
                  />
                  <button
                    onClick={handleComment}
                    disabled={!commentText.trim()}
                    style={{
                      background: commentText.trim() ? 'var(--primary)' : 'transparent',
                      border: 'none',
                      cursor: commentText.trim() ? 'pointer' : 'default',
                      padding: '0 14px',
                      color: commentText.trim() ? 'white' : 'var(--text-muted)',
                      fontSize: '13px',
                      fontWeight: 700,
                      fontFamily: 'inherit',
                      transition: 'var(--transition)',
                    }}
                  >
                    Gá»­i
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}
    </article>
  );
}

