import { useState, useEffect, useCallback } from 'react';
import { STORAGE_KEYS } from '@/constants/storageKeys';
import { timeAgo } from '@/utils';

function buildNotifications(userId) {
  const groups = JSON.parse(localStorage.getItem(STORAGE_KEYS.GROUPS) || '[]');
  const joinedIds = groups.filter(g => g.members.includes(userId)).map(g => g.id);
  const groupMap = Object.fromEntries(groups.map(g => [g.id, g.name]));

  const allSchedules = JSON.parse(localStorage.getItem(STORAGE_KEYS.SCHEDULES) || '[]');
  const allDeadlines = JSON.parse(localStorage.getItem(STORAGE_KEYS.DEADLINES) || '[]');
  const allInvites = JSON.parse(localStorage.getItem(STORAGE_KEYS.GROUP_INVITES) || '[]');
  const allFriendReqs = JSON.parse(localStorage.getItem(STORAGE_KEYS.FRIENDS) || '[]');
  const allUsers = JSON.parse(localStorage.getItem(STORAGE_KEYS.USERS) || '[]');

  const now = new Date();
  const ONE_MIN_MS = 60 * 1000;
  const ONE_DAY_MS = 24 * 60 * 60 * 1000;
  const notifs = [];

  // Friend requests pending
  allFriendReqs
    .filter(f => {
      if (Number(f.toUserId) !== Number(userId) || f.status !== 'pending') return false;
      return (now - new Date(f.createdAt)) < ONE_DAY_MS;
    })
    .forEach(f => {
      const sender = allUsers.find(u => Number(u.id) === Number(f.fromUserId));
      const senderName = sender?.fullName || 'Ai Ä‘Ă³';
      notifs.push({
        key: `friendreq:${f.id}`,
        type: 'friendreq',
        title: 'đŸ¤ Lá»i má»i káº¿t báº¡n',
        body: `${senderName} muá»‘n káº¿t báº¡n vá»›i báº¡n`,
        createdAt: f.createdAt,
        requestId: f.id,
        fromUserId: f.fromUserId,
        fromUserName: senderName,
      });
    });

  // Group invites pending
  allInvites
    .filter(inv => {
      if (Number(inv.toUserId) !== Number(userId) || inv.status !== 'pending') return false;
      return (now - new Date(inv.createdAt)) < ONE_MIN_MS;
    })
    .forEach(inv => {
      notifs.push({
        key: `groupinvite:${inv.id}`,
        type: 'groupinvite',
        title: 'đŸ‘¥ Lá»i má»i vĂ o nhĂ³m',
        body: `${inv.fromUserName} má»i báº¡n tham gia nhĂ³m "${inv.groupName}"`,
        createdAt: inv.createdAt,
        inviteId: inv.id,
        groupId: inv.groupId,
        groupName: inv.groupName,
      });
    });

  // Schedules created in 24 hours
  allSchedules
    .filter(s => joinedIds.includes(s.groupId) && new Date(s.dateTime) >= now
      && (now - new Date(s.createdAt)) < ONE_DAY_MS)
    .forEach(s => {
      notifs.push({
        key: `schedule:${s.id}`,
        type: 'schedule',
        title: `đŸ“… Lá»‹ch há»c má»›i: "${s.topic}"`,
        body: `NhĂ³m ${groupMap[s.groupId] || 'há»c'} â€¢ ${new Date(s.dateTime).toLocaleString('vi-VN')}`,
        createdAt: s.createdAt,
        groupId: s.groupId,
      });
    });

  // Deadlines created in 24 hours
  allDeadlines
    .filter(d => {
      if (!joinedIds.includes(d.groupId) || d.completed) return false;
      if ((now - new Date(d.createdAt)) >= ONE_DAY_MS) return false;
      if (d.assigneeId && d.assigneeId !== 'all') {
        return String(d.assigneeId) === String(userId);
      }
      return true;
    })
    .forEach(d => {
      const isPersonal = d.assigneeId && d.assigneeId !== 'all';
      notifs.push({
        key: `deadline:${d.id}`,
        type: 'deadline',
        title: `â° Deadline má»›i: "${d.title}"`,
        body: `${isPersonal ? 'đŸ‘¤ Giao cho báº¡n' : 'đŸŒ Cáº£ nhĂ³m'} â€¢ NhĂ³m ${groupMap[d.groupId] || 'há»c'} â€¢ Háº¡n: ${new Date(d.dueDate).toLocaleString('vi-VN')}`,
        createdAt: d.createdAt,
        groupId: d.groupId,
      });
    });

  // Deadlines due in 24 hours (Urgent warning)
  allDeadlines
    .filter(d => {
      if (!joinedIds.includes(d.groupId) || d.completed) return false;
      const due = new Date(d.dueDate).getTime();
      const timeLeft = due - now.getTime();
      if (!(timeLeft > 0 && timeLeft <= ONE_DAY_MS)) return false;
      if (d.assigneeId && d.assigneeId !== 'all') {
        return String(d.assigneeId) === String(userId);
      }
      return true;
    })
    .forEach(d => {
      const due = new Date(d.dueDate).getTime();
      const timeLeft = due - now.getTime();
      const hoursLeft = Math.floor(timeLeft / (1000 * 60 * 60));
      const minutesLeft = Math.floor((timeLeft % (1000 * 60 * 60)) / (1000 * 60));
      const timeStr = hoursLeft > 0 ? `${hoursLeft} giá» ${minutesLeft} phĂºt` : `${minutesLeft} phĂºt`;
      const isPersonal = d.assigneeId && d.assigneeId !== 'all';
      notifs.push({
        key: `deadline-urgent:${d.id}`,
        type: 'deadline-urgent',
        title: `đŸ¨ ${isPersonal ? 'Deadline cá»§a báº¡n' : 'Deadline nhĂ³m'} sáº¯p Ä‘áº¿n: "${d.title}"`,
        body: `${isPersonal ? 'đŸ‘¤ Giao cho báº¡n' : 'đŸŒ Cáº£ nhĂ³m'} â€¢ NhĂ³m ${groupMap[d.groupId] || 'há»c'} â€¢ CĂ²n ${timeStr} â€¢ Háº¡n: ${new Date(d.dueDate).toLocaleString('vi-VN')}`,
        createdAt: new Date(new Date(d.dueDate).getTime() - ONE_DAY_MS).toISOString(),
        groupId: d.groupId,
        deadlineId: d.id,
        dueDate: d.dueDate,
      });
    });

  notifs.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
  return notifs;
}

export default function useNotifications(userId) {
  const [notifs, setNotifs] = useState([]);
  const [seen, setSeen] = useState(() => {
    try {
      return new Set(JSON.parse(localStorage.getItem(STORAGE_KEYS.NOTIF_SEEN)) || []);
    } catch {
      return new Set();
    }
  });
  const [processing, setProcessing] = useState({});

  const refresh = useCallback(() => {
    if (!userId) return;
    setNotifs(buildNotifications(userId));
    try {
      setSeen(new Set(JSON.parse(localStorage.getItem(STORAGE_KEYS.NOTIF_SEEN)) || []));
    } catch {
      setSeen(new Set());
    }
  }, [userId]);

  useEffect(() => {
    refresh();
    const interval = setInterval(refresh, 5000);
    return () => clearInterval(interval);
  }, [refresh]);

  const markAllRead = useCallback(() => {
    const newSeen = new Set([...seen, ...notifs.map(n => n.key)]);
    localStorage.setItem(STORAGE_KEYS.NOTIF_SEEN, JSON.stringify([...newSeen]));
    setSeen(newSeen);
  }, [seen, notifs]);

  const acceptInvite = useCallback(async (inviteId, groupId) => {
    setProcessing(p => ({ ...p, [inviteId]: 'accepting' }));

    // Update invite status
    const invites = JSON.parse(localStorage.getItem(STORAGE_KEYS.GROUP_INVITES) || '[]');
    const idx = invites.findIndex(i => i.id === inviteId);
    if (idx !== -1) {
      invites[idx].status = 'accepted';
      invites[idx].respondedAt = new Date().toISOString();
      localStorage.setItem(STORAGE_KEYS.GROUP_INVITES, JSON.stringify(invites));
    }

    // Join group
    const groups = JSON.parse(localStorage.getItem(STORAGE_KEYS.GROUPS) || '[]');
    const gIdx = groups.findIndex(g => g.id === groupId);
    if (gIdx !== -1) {
      const numId = Number(userId);
      const alreadyIn = groups[gIdx].members.some(m => Number(m) === numId);
      if (!alreadyIn) {
        groups[gIdx].members.push(numId);
        localStorage.setItem(STORAGE_KEYS.GROUPS, JSON.stringify(groups));
      }
    }

    setProcessing(p => ({ ...p, [inviteId]: null }));
    refresh();
  }, [userId, refresh]);

  const declineInvite = useCallback(async (inviteId) => {
    setProcessing(p => ({ ...p, [inviteId]: 'declining' }));

    const invites = JSON.parse(localStorage.getItem(STORAGE_KEYS.GROUP_INVITES) || '[]');
    const idx = invites.findIndex(i => i.id === inviteId);
    if (idx !== -1) {
      invites[idx].status = 'declined';
      invites[idx].respondedAt = new Date().toISOString();
      localStorage.setItem(STORAGE_KEYS.GROUP_INVITES, JSON.stringify(invites));
    }

    setProcessing(p => ({ ...p, [inviteId]: null }));
    refresh();
  }, [refresh]);

  const acceptFriendRequest = useCallback(async (requestId) => {
    setProcessing(p => ({ ...p, [requestId]: 'accepting' }));

    const friends = JSON.parse(localStorage.getItem(STORAGE_KEYS.FRIENDS) || '[]');
    const idx = friends.findIndex(f => f.id === requestId);
    if (idx !== -1) {
      friends[idx].status = 'accepted';
      friends[idx].acceptedAt = new Date().toISOString();
      localStorage.setItem(STORAGE_KEYS.FRIENDS, JSON.stringify(friends));
    }

    setProcessing(p => ({ ...p, [requestId]: null }));
    refresh();
  }, [refresh]);

  const declineFriendRequest = useCallback(async (requestId) => {
    setProcessing(p => ({ ...p, [requestId]: 'declining' }));

    const friends = JSON.parse(localStorage.getItem(STORAGE_KEYS.FRIENDS) || '[]').filter(f => f.id !== requestId);
    localStorage.setItem(STORAGE_KEYS.FRIENDS, JSON.stringify(friends));

    setProcessing(p => ({ ...p, [requestId]: null }));
    refresh();
  }, [refresh]);

  const unreadCount = notifs.filter(n => !seen.has(n.key)).length;

  return {
    notifs,
    seen,
    unreadCount,
    processing,
    refresh,
    markAllRead,
    acceptInvite,
    declineInvite,
    acceptFriendRequest,
    declineFriendRequest
  };
}

