  useEffect(() => {
    if (!h.group) return;
    const params = new URLSearchParams(window.location.search);
    const tab = params.get('tab');
    if (tab === 'schedule' || tab === 'deadlines') {
      setTimeout(() => h.setActiveTab(tab), 0);
    }
  }, [h.group]); // eslint-disable-line react-hooks/exhaustive-deps

