              {h.group.creatorId === user?.id && <span style={{ fontSize: '11px', fontWeight: 700, textTransform: 'uppercase', padding: '4px 12px', borderRadius: '6px', background: 'rgba(245,158,11,0.1)', color: '#f59e0b', border: '1px solid rgba(245,158,11,0.25)' }}>TrÆ°á»Ÿng nhĂ³m</span>}
              {h.group.deputyId === user?.id && <span style={{ fontSize: '11px', fontWeight: 700, textTransform: 'uppercase', padding: '4px 12px', borderRadius: '6px', background: 'rgba(108,99,255,0.1)', color: 'var(--primary-light)', border: '1px solid rgba(108,99,255,0.25)' }}>PhĂ³ nhĂ³m</span>}
