                <span style={{ fontSize: '12px', color: 'var(--text-muted)' }}>thĂ nh viĂªn</span>
              </div>
            </div>
          </div>
        </div>

        {/* â”€â”€ Tab Navigation â”€â”€ */}
        <div className="profile-tabs" style={{ marginBottom: '32px' }}>
