            { key: 'deadlines', label: 'â° Deadline & CĂ´ng viá»‡c', badge: urgentCount },
            { key: 'chat',      label: 'đŸ’¬ TrĂ² chuyá»‡n nhĂ³m' },
            { key: 'members',   label: 'đŸ‘¥ ThĂ nh viĂªn' },
          ].map(({ key, label, badge }) => (
            <button
              key={key}
              className={`profile-tab ${h.activeTab === key ? 'active' : ''}`}
              onClick={() => {
                h.setActiveTab(key);
