import { useState, useEffect, useCallback } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '@/context/AuthContext';
import { getUserSchedulesAndDeadlines } from '@/services/interactionService';
import { getTotalUnread } from '@/services/chatServiceTEMP';
import { STORAGE_KEYS } from '@/constants/storageKeys';
import AppLayout from '@/layouts/AppLayout';
import Avatar from '@/components/common/Avatar';
import NotificationBell from '@/components/notifications/NotificationBell';
import PostList from '@/components/posts/PostList';
import CreatePostModal from '@/components/posts/CreatePostModal';

const NAV_ITEMS = [
  { icon: 'đŸ ', label: 'Trang chá»§', to: '/', key: 'home' },
  { icon: 'đŸ‘¥', label: 'NhĂ³m há»c', to: '/groups', key: 'groups' },
  { icon: 'đŸ“…', label: 'Lá»‹ch & Deadline', to: '/schedule', key: 'schedule' },
  { icon: 'đŸ¤', label: 'Káº¿t báº¡n', to: '/friends', key: 'friends' },
  { icon: 'đŸ“', label: 'TĂ i liá»‡u', to: '/my-documents', key: 'docs' },
  { icon: 'đŸ’¬', label: 'Nháº¯n tin', to: '/chat', key: 'chat' },
];

export default function Home() {
  const { user } = useAuth();
  const [posts, setPosts] = useState([]);
  const [search, setSearch] = useState('');
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [chatUnread, setChatUnread] = useState(0);
  const [pendingFriendsCount, setPendingFriendsCount] = useState(0);
  const [schedules, setSchedules] = useState([]);
  const [deadlines, setDeadlines] = useState([]);

  // Fetch local posts
  const fetchPosts = useCallback(() => {
    try {
      const data = JSON.parse(
        localStorage.getItem(STORAGE_KEYS.GLOBAL_POSTS) ||
        localStorage.getItem(STORAGE_KEYS.POSTS) ||
        '[]'
      );
      setPosts(data);
    } catch {
      setPosts([]);
    }
  }, []);

  const fetchSideData = useCallback(async () => {
    if (!user?.id) return;
    try {
      // Unread chats
      const unread = await getTotalUnread(user.id);
      setChatUnread(unread);

      // Friends pending reqs
      const friends = JSON.parse(localStorage.getItem(STORAGE_KEYS.FRIENDS) || '[]');
      const pendingCount = friends.filter(
        (f) => Number(f.toUserId) === Number(user.id) && f.status === 'pending'
      ).length;
      setPendingFriendsCount(pendingCount);

      // User schedule & deadlines
      const { schedules: schedList, deadlines: deadList } = await getUserSchedulesAndDeadlines(user.id);

      // Filter upcoming schedules
      const now = Date.now();
      const upcomingSched = schedList
        .filter((s) => new Date(s.dateTime) >= now)
        .sort((a, b) => new Date(a.dateTime) - new Date(b.dateTime))
        .slice(0, 3);
      setSchedules(upcomingSched);

      // Filter incomplete deadlines due soon
      const oneDayMs = 24 * 60 * 60 * 1000;
      const incompleteDead = deadList
        .filter((d) => !d.completed)
        .map((d) => {
          const due = new Date(d.dueDate).getTime();
          return {
            ...d,
            dueSoon: due > now && due - now <= oneDayMs,
            overdue: due < now,
          };
        })
        .sort((a, b) => new Date(a.dueDate) - new Date(b.dueDate))
        .slice(0, 4);
      setDeadlines(incompleteDead);
    } catch (err) {
      console.warn('Error fetching side panel data:', err);
    }
  }, [user?.id]);

  useEffect(() => {
    fetchPosts();
    fetchSideData();

    const interval = setInterval(fetchSideData, 6000);
    return () => clearInterval(interval);
  }, [fetchPosts, fetchSideData]);

  // Post handlers
  const handleLikePost = (postId, emoji) => {
    const updated = posts.map((p) => {
      if (p.id !== postId) return p;
      const likes = Array.isArray(p.likes) ? [...p.likes] : [];
      const idx = likes.findIndex(
        (l) => (typeof l === 'object' ? l.userId : l) === user?.id
      );

      if (idx >= 0) {
        if (emoji) {
          likes[idx] = { userId: user.id, emoji };
        } else {
          likes.splice(idx, 1);
        }
      } else if (emoji) {
        likes.push({ userId: user.id, emoji });
      }
      return { ...p, likes };
    });
    setPosts(updated);
    localStorage.setItem(STORAGE_KEYS.GLOBAL_POSTS || STORAGE_KEYS.POSTS, JSON.stringify(updated));
  };

  const handleDeletePost = (postId) => {
    if (!window.confirm('Báº¡n cĂ³ cháº¯c cháº¯n muá»‘n xĂ³a cĂ¢u há»i nĂ y?')) return;
    const updated = posts.filter((p) => p.id !== postId);
    setPosts(updated);
    localStorage.setItem(STORAGE_KEYS.GLOBAL_POSTS || STORAGE_KEYS.POSTS, JSON.stringify(updated));
  };

  const handleCommentPost = (postId, content, replyTo = null) => {
    const updated = posts.map((p) => {
      if (p.id !== postId) return p;
      const comments = Array.isArray(p.comments) ? [...p.comments] : [];
      comments.push({
        id: Date.now().toString(),
        userId: user.id,
        userFullName: user.fullName,
        userAvatar: user.avatar || '',
        userInitial: (user.fullName || 'U')[0].toUpperCase(),
        content,
        parentId: replyTo?.id || null,
        replyToName: replyTo?.name || null,
        createdAt: new Date().toISOString(),
      });
      return { ...p, comments };
    });
    setPosts(updated);
    localStorage.setItem(STORAGE_KEYS.GLOBAL_POSTS || STORAGE_KEYS.POSTS, JSON.stringify(updated));
  };

  const filteredPosts = posts.filter((p) => {
    const q = search.trim().toLowerCase();
    if (!q) return true;
    return (
      p.content.toLowerCase().includes(q) ||
      (p.tag && p.tag.toLowerCase().includes(q)) ||
      p.userFullName.toLowerCase().includes(q)
    );
  });

  return (
    <AppLayout>
      <div style={{ maxWidth: '1240px', margin: '0 auto', padding: '24px 16px' }}>
        <div style={{ display: 'grid', gridTemplateColumns: '260px 1fr 300px', gap: '24px', alignItems: 'flex-start' }}>

          {/* LEFT COLUMN: Sidebar */}
          <aside style={{ position: 'sticky', top: '80px', display: 'flex', flexDirection: 'column', gap: '2px' }}>
            <div style={{ display: 'flex', alignItems: 'center', background: 'var(--bg-card)', border: '1px solid var(--border)', borderRadius: '14px', marginBottom: '8px', overflow: 'hidden' }}>
              <Link to="/profile" style={{ textDecoration: 'none', flex: 1, minWidth: 0 }}>
                <div
                  style={{ display: 'flex', alignItems: 'center', gap: '8px', padding: '10px 10px 10px 12px', transition: 'var(--transition)' }}
                  onMouseEnter={(e) => (e.currentTarget.style.background = 'rgba(108,99,255,0.08)')}
                  onMouseLeave={(e) => (e.currentTarget.style.background = 'transparent')}
                >
                  <Avatar src={user?.avatar} initial={(user?.fullName || 'U')[0]} size={34} />
                  <div style={{ minWidth: 0 }}>
                    <div style={{ fontWeight: 700, fontSize: '13px', color: 'var(--text-primary)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                      {user?.fullName || 'NgÆ°á»i dĂ¹ng'}
                    </div>
                    <div style={{ fontSize: '11px', color: 'var(--primary-light)', fontWeight: 600 }}>Xem há»“ sÆ¡</div>
                  </div>
                </div>
              </Link>
              <div style={{ width: '1px', height: '32px', background: 'var(--border)', flexShrink: 0 }} />
              {user?.id && <div style={{ flexShrink: 0 }}><NotificationBell userId={user.id} /></div>}
            </div>

            {/* Search */}
            <div
              style={{ display: 'flex', alignItems: 'center', gap: '10px', background: 'var(--bg-card)', border: '1px solid var(--border)', borderRadius: '12px', padding: '9px 14px', marginBottom: '6px', cursor: 'text', transition: 'border-color 0.2s' }}
              onClick={() => document.getElementById('sidebar-search')?.focus()}
              onMouseEnter={(e) => (e.currentTarget.style.borderColor = 'var(--primary)')}
              onMouseLeave={(e) => (e.currentTarget.style.borderColor = 'var(--border)')}
            >
              <span style={{ fontSize: '14px', color: 'var(--text-muted)', flexShrink: 0 }}>đŸ”</span>
              <input
                id="sidebar-search"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                placeholder="TĂ¬m bĂ i viáº¿t..."
                style={{ background: 'none', border: 'none', outline: 'none', flex: 1, color: 'var(--text-primary)', fontSize: '13px', fontFamily: 'inherit' }}
              />
              {search && (
                <button
                  onClick={(e) => { e.stopPropagation(); setSearch(''); }}
                  style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-muted)', fontSize: '13px', padding: 0, lineHeight: 1 }}
                >
                  âœ•
                </button>
              )}
            </div>

            {/* Navigation links */}
            {NAV_ITEMS.map((item) => {
              const loc = window.location.pathname;
              const isActive = item.to === '/' ? loc === '/' : loc.startsWith(item.to);
              const hasUnread = item.key === 'chat' && chatUnread > 0;
              const hasPending = item.key === 'friends' && pendingFriendsCount > 0;
              return (
                <Link key={item.key} to={item.to} style={{ textDecoration: 'none' }}>
                  <div
                    style={{ display: 'flex', alignItems: 'center', gap: '12px', padding: '11px 14px', borderRadius: '12px', background: isActive ? 'rgba(108,99,255,0.15)' : 'none', transition: 'background 0.15s', position: 'relative' }}
                    onMouseEnter={(e) => { if (!isActive) e.currentTarget.style.background = 'var(--bg-input)'; }}
                    onMouseLeave={(e) => { if (!isActive) e.currentTarget.style.background = 'none'; }}
                  >
                    <span style={{ fontSize: '20px', width: '28px', textAlign: 'center', flexShrink: 0, filter: isActive ? 'drop-shadow(0 0 6px rgba(108,99,255,0.6))' : 'none' }}>
                      {item.icon}
                    </span>
                    <span style={{ fontSize: '14px', fontWeight: isActive ? 700 : 500, color: isActive ? 'var(--primary-light)' : 'var(--text-primary)', flex: 1 }}>
                      {item.label}
                    </span>
                    {hasUnread && (
                      <span style={{ background: '#ef4444', color: 'white', fontSize: '10px', fontWeight: 800, padding: '1px 6px', borderRadius: '10px', minWidth: '18px', textAlign: 'center' }}>
                        {chatUnread > 9 ? '9+' : chatUnread}
                      </span>
                    )}
                    {hasPending && (
                      <span style={{ background: '#ef4444', color: 'white', fontSize: '10px', fontWeight: 800, padding: '1px 6px', borderRadius: '10px', minWidth: '18px', textAlign: 'center' }}>
                        {pendingFriendsCount > 9 ? '9+' : pendingFriendsCount}
                      </span>
                    )}
                  </div>
                </Link>
              );
            })}
          </aside>

          {/* MIDDLE COLUMN: Feed */}
          <main style={{ minWidth: 0 }}>
            {/* Create Question Box */}
            <div style={{ background: 'var(--bg-card)', border: '1px solid var(--border)', borderRadius: '18px', padding: '16px 18px', marginBottom: '14px', display: 'flex', gap: '12px', alignItems: 'center' }}>
              <Avatar src={user?.avatar} initial={(user?.fullName || 'U')[0]} size={42} />
              <button
                onClick={() => setShowCreateModal(true)}
                style={{ flex: 1, background: 'var(--bg-input)', border: '1px solid var(--border)', borderRadius: '24px', padding: '12px 18px', color: 'var(--text-muted)', fontSize: '14px', textAlign: 'left', cursor: 'pointer', fontFamily: 'inherit', transition: 'border-color 0.2s, background 0.2s' }}
                onMouseEnter={(e) => { e.currentTarget.style.borderColor = 'rgba(108,99,255,0.4)'; e.currentTarget.style.background = 'var(--border)'; }}
                onMouseLeave={(e) => { e.currentTarget.style.borderColor = 'var(--border)'; e.currentTarget.style.background = 'var(--bg-input)'; }}
              >
                Báº¡n cĂ³ cĂ¢u há»i há»c táº­p nĂ o khĂ´ng? ÄÄƒng ngay...
              </button>
            </div>

            <PostList
              posts={filteredPosts}
              currentUser={user}
              onLike={handleLikePost}
              onDelete={handleDeletePost}
              onComment={handleCommentPost}
            />
          </main>

          {/* RIGHT COLUMN: Schedules & Deadlines widget */}
          <aside style={{ position: 'sticky', top: '80px', display: 'flex', flexDirection: 'column', gap: '14px' }}>
            {/* Upcomming Study sessions */}
            <div style={{ background: 'var(--bg-card)', border: '1px solid var(--border)', borderRadius: '18px', overflow: 'hidden' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '14px 16px 10px' }}>
                <span style={{ fontWeight: 700, fontSize: '14px' }}>đŸ“… Buá»•i há»c sáº¯p tá»›i</span>
                <Link to="/schedule" style={{ fontSize: '13px', color: 'var(--primary-light)', textDecoration: 'none', fontWeight: 700 }}>Táº¥t cáº£</Link>
              </div>
              {schedules.length === 0 ? (
                <div style={{ padding: '24px 16px', textAlign: 'center', color: 'var(--text-muted)', fontSize: '12px' }}>
                  ChÆ°a cĂ³ lá»‹ch há»c nhĂ³m nĂ o
                </div>
              ) : (
                schedules.map((s, i) => (
                  <Link key={s.id} to={`/groups/${s.groupId}?tab=schedule`} style={{ textDecoration: 'none', color: 'inherit' }}>
                    <div
                      style={{ padding: '10px 16px', borderTop: i === 0 ? '1px solid var(--border)' : 'none', transition: 'background 0.15s', cursor: 'pointer' }}
                      onMouseEnter={(e) => (e.currentTarget.style.background = 'rgba(108,99,255,0.08)')}
                      onMouseLeave={(e) => (e.currentTarget.style.background = 'transparent')}
                    >
                      <div style={{ display: 'flex', gap: '10px', alignItems: 'flex-start' }}>
                        <div style={{ width: '36px', height: '36px', borderRadius: '10px', flexShrink: 0, background: 'rgba(108,99,255,0.15)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '16px' }}>đŸ“–</div>
                        <div style={{ flex: 1, minWidth: 0 }}>
                          <div style={{ fontWeight: 600, fontSize: '13px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{s.topic}</div>
                          <div style={{ fontSize: '11px', color: 'var(--text-muted)', marginTop: '3px' }}>
                            đŸ• {new Date(s.dateTime).toLocaleString('vi-VN', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' })}
                          </div>
                          <div style={{ fontSize: '11px', marginTop: '2px', color: 'var(--text-muted)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                            đŸ“ {s.location}
                          </div>
                        </div>
                      </div>
                    </div>
                  </Link>
                ))
              )}
            </div>

            {/* Group Deadlines widget */}
            <div style={{ background: 'var(--bg-card)', border: '1px solid var(--border)', borderRadius: '18px', overflow: 'hidden' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '14px 16px 10px' }}>
                <span style={{ fontWeight: 700, fontSize: '14px' }}>â° Deadline cáº§n ná»™p</span>
                <Link to="/schedule" style={{ fontSize: '13px', color: 'var(--primary-light)', textDecoration: 'none', fontWeight: 700 }}>Xem lá»‹ch</Link>
              </div>
              {deadlines.length === 0 ? (
                <div style={{ padding: '24px 16px', textAlign: 'center', color: 'var(--text-muted)', fontSize: '12px' }}>
                  KhĂ´ng cĂ²n deadline nĂ o
                </div>
              ) : (
                deadlines.map((d, i) => (
                  <Link key={d.id} to={`/groups/${d.groupId}?tab=deadlines`} style={{ textDecoration: 'none', color: 'inherit' }}>
                    <div
                      style={{ padding: '10px 16px', borderTop: i === 0 ? '1px solid var(--border)' : 'none', background: d.dueSoon ? 'rgba(239,68,68,0.04)' : 'none', transition: 'background 0.15s', cursor: 'pointer' }}
                      onMouseEnter={(e) => (e.currentTarget.style.background = d.dueSoon ? 'rgba(239,68,68,0.10)' : 'rgba(108,99,255,0.08)')}
                      onMouseLeave={(e) => (e.currentTarget.style.background = d.dueSoon ? 'rgba(239,68,68,0.04)' : 'transparent')}
                    >
                      <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
                        <div style={{ width: '8px', height: '8px', borderRadius: '50%', flexShrink: 0, background: d.overdue ? '#666' : d.dueSoon ? '#ef4444' : '#22c55e', boxShadow: d.dueSoon ? '0 0 6px #ef4444' : 'none' }} />
                        <div style={{ flex: 1, minWidth: 0 }}>
                          <div style={{ fontSize: '13px', fontWeight: 600, color: d.overdue ? 'var(--text-muted)' : 'var(--text-primary)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{d.title}</div>
                          <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '2px' }}>
                            <span style={{ fontSize: '11px', color: 'var(--text-muted)' }}>đŸ“‚ {d.groupName}</span>
                            <span style={{ fontSize: '11px', fontWeight: 700, color: d.dueSoon ? '#ef4444' : d.overdue ? 'var(--text-muted)' : 'var(--secondary)' }}>
                              {d.dueSoon ? 'â¡ DÆ°á»›i 24h' : new Date(d.dueDate).toLocaleDateString('vi-VN')}
                            </span>
                          </div>
                        </div>
                      </div>
                    </div>
                  </Link>
                ))
              )}
            </div>
          </aside>

        </div>
      </div>

      {showCreateModal && (
        <CreatePostModal
          user={user}
          onClose={() => setShowCreateModal(false)}
          onSubmit={(newPost) => setPosts([newPost, ...posts])}
        />
      )}
    </AppLayout>
  );
}

